parameters.jsCode:
return [{
  json: {
    from: 'angry@customer.com',
    subject: 'URGENT: System is down!!!',
    body: 'This is completely unacceptable. We have been down for 2 hours and no one has responded. This is costing us thousands of dollars. I need this fixed IMMEDIATELY or we are canceling our contract.',
    receivedAt: new Date().toISOString()
  }
}];

const email = $input.first().json;
const body = email.body.toLowerCase();
const subject = email.subject.toLowerCase();

// Priority scoring
let score = 0;
const keywords = {
  critical: ['down', 'outage', 'broken', 'not working', 'emergency'],
  urgent: ['urgent', 'asap', 'immediately', 'critical'],
  angry: ['unacceptable', 'cancel', 'refund', 'escalate', 'manager']
};

if (keywords.critical.some(k => body.includes(k) || subject.includes(k))) score += 3;
if (keywords.urgent.some(k => body.includes(k) || subject.includes(k))) score += 2;
if (keywords.angry.some(k => body.includes(k))) score += 2;

let priority = 'LOW';
if (score >= 5) priority = 'CRITICAL';
else if (score >= 3) priority = 'HIGH';
else if (score >= 1) priority = 'MEDIUM';

return [{
  json: {
    ...email,
    triageScore: score,
    priority,
    category: score >= 5 ? 'OUTAGE' : score >= 3 ? 'URGENT_BUG' : 'GENERAL'
  }
}];

